1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty input returns empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation ã [(0,0)] ã []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation ã [(0,1),(1,1)] ã []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 1 Underpopulation: live cell with fewer than 2 neighbors dies ã diagonal pair [(0,0),(1,1)] ã []", () => {
15	    expect(nextGeneration([[0, 0], [1, 1]])).toEqual([]);
16	  });
17	  it("Rule 2 Survival: live cell with 2 neighbors lives on ã L-shape [(0,0),(1,0),(0,1)] becomes block [(0,0),(1,0),(0,1),(1,1)]", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
19	    expect(result.sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
20	  });
21	  it("Rule 3 Overpopulation: center of full 3x3 dies ã center (1,1) not in next generation", () => {
22	    const full3x3: Cell[] = [
23	      [0, 0], [1, 0], [2, 0],
24	      [0, 1], [1, 1], [2, 1],
25	      [0, 2], [1, 2], [2, 2],
26	    ];
27	    const result = nextGeneration(full3x3);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it.todo("Rule 4 Reproduction: dead cell with exactly 3 neighbors becomes alive ã L-shape produces new cell");
31	  it.todo("Block still life remains unchanged ã [(0,0),(1,0),(0,1),(1,1)] stays the same");
32	  it.todo("Blinker oscillator rotates ã vertical [(0,0),(0,1),(0,2)] ã horizontal [(-1,1),(0,1),(1,1)]");
33	  it.todo("handles negative coordinates correctly");
34	});
35

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	const parseKey = (k: string): Cell => k.split(",").map(Number) as Cell;
11	
12	const survivesOrIsBorn = (isAlive: boolean, neighborCount: number): boolean =>
13	  neighborCount === 3 || (isAlive && neighborCount === 2);
14	
15	export function nextGeneration(liveCells: Cell[]): Cell[] {
16	  const liveKeys = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
17	  const neighborCounts = new Map<string, number>();
18	
19	  for (const [x, y] of liveCells) {
20	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
21	      const k = cellKey(x + dx, y + dy);
22	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
23	    }
24	  }
25	
26	  const nextCells: Cell[] = [];
27	  for (const [k, count] of neighborCounts) {
28	    if (survivesOrIsBorn(liveKeys.has(k), count)) {
29	      nextCells.push(parseKey(k));
30	    }
31	  }
32	  return nextCells;
33	}
